SELECT history_id as historyId, database_id as databaseId, instance_id as instanceId, table_name as tableName, schema_name as schemaName, vacuum_type as vacuumType, executed_at as executedAt, duration_seconds as durationSeconds, dead_tuples_before as deadTuplesBefore, bloat_ratio_before as bloatRatioBefore, status FROM vacuum_history WHERE executed_at BETWEEN #{start} AND #{end}
AND database_id = #{databaseId}
ORDER BY executed_at DESC

